package ai.service;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Paths;
import java.util.List;

public class CodeExtractor {

    private static final int CONTEXT_LINES = 20;

    public static String extractCode(String filePath, int issueLine) throws IOException {

        List<String> lines = Files.readAllLines(Paths.get(filePath));

        if (lines.isEmpty()) {
            return "";
        }

        int lineIndex = Math.max(0, issueLine - 1);

        int methodStart = findMethodStart(lines, lineIndex);
        int methodEnd = findMethodEnd(lines, methodStart);

        if (methodStart != -1 && methodEnd != 1) {

            StringBuilder builder = new StringBuilder();

            int start = Math.max(0, methodStart - CONTEXT_LINES);
            int end = Math.min(lines.size() - 1, methodEnd + CONTEXT_LINES);

            for (int i = start; i < end; i++) {
                builder.append(lines.get(i)).append("\n");
            }

            return builder.toString();
        }

        return "";
    }

    private static int findMethodStart(List<String> lines, int lineIndex) {
        for (int i = lineIndex; i >= 0; i--) {
            String line = lines.get(i);
            if (line.trim().matches("^[\\s\\t]*public static void main\\(String\\[] args\\)$")) {
                return i;
            }
            if (line.trim().matches("^[\\s\\t]*public void")) {
                return i;
            }
            if (line.trim().matches("^[\\s\\t]*private void")) {
                return i;
            }
            if (line.trim().matches("^[\\s\\t]*void")) {
                return i;
            }
            if (line.trim().matches("^[\\s\\t]*public static")) {
                return i;
            }
            if (line.trim().matches("^[\\s\\t]*public")) {
                return i;
            }
            if (line.trim().matches("^[\\s\\t]*private")) {
                return i;
            }
        }
        return -1;
    }

    private static int findMethodEnd(List<String> lines, int methodStart) {
        int end = methodStart;
        while (end < lines.size()) {
            String line = lines.get(end);
            if (line.trim().endsWith("}")) {
                return end;
            }
            end++;
        }
        return 1;
    }
}
